const items = $input.all();

return items.map(item => {
  const data = item.json;
  let imageUrl = '';

  if (data?.data?.resultJson) {
    try {
      const parsed = JSON.parse(data.data.resultJson);
      imageUrl = (parsed.resultUrls || parsed.originUrls || [])[0] || '';
    } catch(e) { imageUrl = ''; }
  }

  if (!imageUrl) {
    throw new Error('이미지 URL 추출 실패: ' + JSON.stringify(data).substring(0, 500));
  }

  return { json: { ...data, images: [{ url: imageUrl }] } };
});

const items = $input.all();
const segments = $('세그먼트 분리').all();

return items.map((item, i) => {
  const data = item.json;
  const seg = segments[i]?.json || {};
  const veo3Prompt = seg.veo3_prompt || '';
  const imageUrl = data.images?.[0]?.url || '';

  // 큰따옴표, 백슬래시, 줄바꿈 등 JSON 깨뜨리는 문자 제거
  const safePrompt = veo3Prompt.replace(/[\\"]/g, "'").replace(/[\n\r\t]/g, ' ').trim();

  if (!safePrompt) {
    throw new Error('veo3_prompt 없음! segment ' + i + ', keys: ' + Object.keys(seg).join(','));
  }
  if (!imageUrl) {
    throw new Error('imageUrl 없음! item ' + i);
  }

  return {
    json: {
      ...data,
      veo3Body: {
        prompt: safePrompt,
        imageUrls: [imageUrl],
        model: "veo3_fast",
        generationType: "FIRST_AND_LAST_FRAMES_2_VIDEO",
        aspect_ratio: "16:9",
        enableTranslation: false
      }
    }
  };
});
